<template>
    <v-container fluid>
        <v-row dense>
            <v-col cols="6">
                <v-card>
                    <v-card-text>レート</v-card-text>
                    <v-card-text>
                        <radar :name="analyzePlayerData.name" :labels="labelsRate" :datasets="datasetsRate" :datasetsAve="datasetsRateAve" :maxValue="maxValue" :minValue="minValue"></radar>
                    </v-card-text>
                </v-card>
            </v-col>

            <v-col cols="6">
                <v-card>
                    <!-- <v-card-text>失点詳細割合</v-card-text>
                    <v-card-text>
                        <doughnut :labels="labelsBlockMissPercent" :datasets="datasetsBlockMissPercent"></doughnut>
                    </v-card-text> -->
                </v-card>
            </v-col>
        </v-row>
    </v-container>
</template>

<script>
import radar from "../Chart/Radar";

export default {
    name: "analyze_detail_rate",
    props: {
        analyzePlayerData: Object,
        analyzeAllData: Array
    },
    components: {
        radar
    },
    data() {
        return {
            labelsRate: [],
            datasetsRate: [],
            serveRank: 1,
            spikeRank: 1,
            blockRank: 1,
            otherRank: 1,
            datasetsRateAve: [],
            serveRankAve: 1,
            spikeRankAve: 1,
            blockRankAve: 1,
            otherRankAve: 1,
            minValue: 0,
            maxValue: 100
        };
    },
    beforeMount() {
        this.formatRateData();
    },
    methods: {
        formatRateData() {
            this.labelsRate = ["スパイク", "ブロック", "その他ミス", "サーブ"];
            this.rateScore();
            this.datasetsRate = [this.spikeRank, this.blockRank, this.otherRank, this.serveRank];
            this.datasetsRateAve = [this.spikeRankAve, this.blockRankAve, this.otherRankAve, this.serveRankAve];
        },
        rateScore() {
            var serveScore = this.calc(this.analyzePlayerData.serve.point, this.analyzePlayerData.serve.miss);
            var spikeScore = this.calc(this.analyzePlayerData.spike.point, this.analyzePlayerData.spike.miss);
            var blockScore = this.calc(this.analyzePlayerData.block.point, this.analyzePlayerData.block.miss);
            var otherScore = this.analyzePlayerData.receive.miss + this.analyzePlayerData.other_miss + this.analyzePlayerData.faul;

            // console.log("serveScore[" + serveScore + "]spikeScore[" + spikeScore + "]blockScore[" + blockScore + "]otherScore[" + otherScore + "]");

            this.serveRank = 1;
            this.spikeRank = 1;
            this.blockRank = 1;
            this.otherRank = 1;

            var serveRankTemp = 1;
            var spikeRankTemp = 1;
            var blockRankTemp = 1;
            var otherRankTemp = 1;
            for (var i = 0; i < this.analyzeAllData.length; i++) {
                if (this.analyzeAllData[i].playerid != this.analyzePlayerData.playerid) {
                    if (this.calc(this.analyzeAllData[i].serve.point, this.analyzeAllData[i].serve.miss) > serveScore) {
                        serveRankTemp++;
                    }
                    if (this.calc(this.analyzeAllData[i].spike.point, this.analyzeAllData[i].spike.miss) > spikeScore) {
                        spikeRankTemp++;
                    }
                    if (this.calc(this.analyzeAllData[i].block.point, this.analyzeAllData[i].block.miss) > blockScore) {
                        blockRankTemp++;
                    }
                    if (this.analyzeAllData[i].receive.miss + this.analyzeAllData[i].other_miss + this.analyzeAllData[i].faul < otherScore) {
                        otherRankTemp++;
                    }
                }
            }
            this.serveRank = 100 - (serveRankTemp / this.analyzeAllData.length) * 100;
            this.spikeRank = 100 - (spikeRankTemp / this.analyzeAllData.length) * 100;
            this.blockRank = 100 - (blockRankTemp / this.analyzeAllData.length) * 100;
            this.otherRank = (otherRankTemp / this.analyzeAllData.length) * 100;
            // console.log(
            //     "serveRank[" + this.serveRank + "]spikeRank[" + this.spikeRank + "]blockRank[" + this.blockRank + "]otherRank[" + this.otherRank + "]"
            // );
        },
        calc(point, miss) {
            return point - miss * 0.75;
        }
    }
};
</script>
