<template>
    <v-card>
        <v-dialog v-model="isShow" persistent>
            <v-card>
                <v-card-title class="headline primary" style="color:white;" primary-title dark>メンバーチェンジ</v-card-title>

                <v-container>
                    <v-row>
                        <v-col cols="6" class="member-select-area">
                            <ul>
                                <li class="member">
                                    <input type="radio" id="mem_x" name="member" v-on:change="onChangeMember(null)" value="-1" v-model="modelSelection" />
                                    <label for="mem_x">
                                        <v-btn v-show="modelSelection == -1" class="button-member" height="100%" color="primary" dark>空に変更</v-btn>
                                        <v-btn
                                            v-on:click="
                                                modelSelection = -1;
                                                onChangeMember(null);
                                            "
                                            v-show="modelSelection != -1"
                                            class="button-member"
                                            height="100%"
                                            >空に変更</v-btn
                                        >
                                    </label>
                                </li>
                                <li class="member">
                                    <input type="radio" id="mem_y" name="member" v-on:change="onChangeMember(null)" value="-2" v-model="modelSelection" />
                                    <label for="mem_y">
                                        <v-btn v-show="modelSelection == -2" class="button-member" height="100%" color="primary" dark>１つずらす</v-btn>
                                        <v-btn
                                            v-on:click="
                                                modelSelection = -2;
                                                onChangeMember(null);
                                            "
                                            v-show="modelSelection != -2"
                                            class="button-member"
                                            height="100%"
                                            >１つずらす</v-btn
                                        >
                                    </label>
                                </li>
                                <li class="member" v-for="member of dialogProp.members" :key="member.playerid">
                                    <input
                                        type="radio"
                                        v-bind:id="'mem_' + member.playerid"
                                        name="member"
                                        v-on:change="onChangeMember(member)"
                                        v-bind:value="member.playerid"
                                        v-model="modelSelection"
                                    />
                                    <label v-bind:for="'mem_' + member.playerid">
                                        <v-btn v-show="modelSelection == member.playerid" class="button-member" height="100%" color="primary" dark>{{ member.no }}:{{ member.name }}</v-btn>
                                        <v-btn
                                            v-on:click="
                                                modelSelection = member.playerid;
                                                onChangeMember(member);
                                            "
                                            v-show="modelSelection != member.playerid"
                                            class="button-member"
                                            height="100%"
                                            >{{ member.no }}:{{ member.name }}</v-btn
                                        >
                                        <playerSvg v-if="member.sex == 0"></playerSvg>
                                        <playerFSvg v-else></playerFSvg>
                                    </label>
                                </li>
                            </ul>
                        </v-col>
                        <v-col cols="6" class="coat" style="height:420px;">
                            <player
                                v-on:on-click-player="changeMember(item, idx, 'a')"
                                v-bind:item="item"
                                v-bind:idx="idx + 1"
                                v-bind:class="item.classGrid"
                                v-for="(item, idx) of itemTeamAWork"
                                :key="item.key"
                            ></player>

                            <player
                                v-on:on-click-player="changeMember(item, idx, 'b')"
                                v-bind:item="item"
                                v-bind:idx="idx + 1"
                                v-bind:class="item.classGrid"
                                v-for="(item, idx) of itemTeamBWork"
                                :key="item.key"
                            ></player>
                        </v-col>
                    </v-row>
                </v-container>
                <v-card-actions>
                    <v-spacer></v-spacer>
                    <v-btn v-on:click="sendResult(true)" color="primary" dark>OK</v-btn>
                    <v-btn v-on:click="sendResult(false)">キャンセル</v-btn>
                </v-card-actions>
            </v-card>
        </v-dialog>
    </v-card>
</template>

<script>
import playerSvg from "../SVG/PlayerSVG";
import playerFSvg from "../SVG/PlayerFSVG";
import player from "../Material/Player";

export default {
    name: "member_change",
    components: {
        playerSvg,
        playerFSvg,
        player
    },
    data() {
        return {
            modelSelection: -1,
            selectedMember: null,
            itemTeamAWork: Array,
            itemTeamBWork: Array,
            dialogProp: {},
            isShow: false,
            scoreSettings: {}
        };
    },
    mounted() {
        this.scoreSettings = this.getScoreSettingsData();
    },
    methods: {
        open(dialogProp) {
            this.dialogProp = dialogProp;
            this.itemTeamAWork = JSON.parse(JSON.stringify(dialogProp.itemTeamA));
            this.itemTeamBWork = JSON.parse(JSON.stringify(dialogProp.itemTeamB));
            this.isShow = true;
        },
        onChangeMember(member) {
            this.selectedMember = member;
        },
        changeMember(item, idx, team) {
            if (this.selectedMember == null) {
                if (this.modelSelection == "-2") {
                    this.shiftNo(idx, team);
                }
                item.playerid = "";
                item.no = "";
                item.name = "";
                item.sex = 0;
                item.isEmpty = true;
            } else {
                item.playerid = this.selectedMember.playerid;
                item.no = this.selectedMember.no;
                item.name = this.selectedMember.name;
                item.sex = this.selectedMember.sex;
                item.isEmpty = false;
            }
        },
        shiftNo(idx, team) {
            var arrayTeam;
            if (team == "a") {
                arrayTeam = this.itemTeamAWork;
            } else {
                arrayTeam = this.itemTeamBWork;
            }
            var tail;
            if (this.scoreSettings.isLibero) {
                tail = 5;
            } else {
                tail = 7;
            }
            for (var i = tail; i > idx; i--) {
                arrayTeam[i].playerid = arrayTeam[i - 1].playerid;
                arrayTeam[i].no = arrayTeam[i - 1].no;
                arrayTeam[i].name = arrayTeam[i - 1].name;
                arrayTeam[i].sex = arrayTeam[i - 1].sex;
                arrayTeam[i].isEmpty = arrayTeam[i - 1].isEmpty;
            }
        },
        sendResult(flg) {
            this.isShow = false;

            if (flg) {
                this.dialogProp.itemTeamA = this.itemTeamAWork;
                this.dialogProp.itemTeamB = this.itemTeamBWork;
            }

            this.dialogProp.callback(flg);
        }
    }
};
</script>

