    overflow-x: hidden;
    overflow-y: scroll;
    height: 420px;
}

.member {
    list-style: none;
    width: 95%;

    input {
        display: none;
    }

    label {
        color: #333;
        display: inline-block;
        width: 100%;
        height: 40px;
        position: relative;

        .button-member {
            position: absolute;
            top: 0;
            right: 0;
            bottom: 0;
            left: 0;
            width: 100%;
            text-align: center;
        }

        svg {
            position: absolute;
            top: 0;
            left: 0;
            bottom: 0;
            height: 100%;
            pointer-events: none;
        }
    }
}
</style>
